SELECT performance_rating, COUNT(*) AS student_count
FROM performance_assessments
GROUP BY performance_rating;

SELECT career_readiness_status, COUNT(*) AS number_of_students
FROM career_readiness
GROUP BY career_readiness_status;

SELECT COUNT(*) 
FROM performance_assessments 
WHERE assessment_date < '2023-05-01';

SELECT student_id
FROM career_readiness
WHERE career_readiness_status = 'Ready';

SELECT COUNT(*) AS total_ready_students
FROM career_readiness
WHERE career_readiness_status = 'Ready';

SELECT student_id, name, email
FROM students
WHERE student_id IN (SELECT user_id FROM user_roles WHERE role_id = 2);
